# Squares Background

Canvas-rendered animated grid of square tiles that drift in a configurable direction and highlight on hover. No external dependencies — pure React and Canvas API.

## Use when
- Filling a dark landing page with a structured, animated background.
- Adding a subtle geometric texture behind a hero or section.
- Providing a neutral animated backdrop without heavy library overhead.

## Stack
- Framework: react
- Libraries: none

## Install
```bash
none
```

## Component — squares-background.tsx
```tsx
import React, { useEffect, useRef } from 'react';

export interface SquaresProps {
  speed?: number;
  squareSize?: number;
  direction?: 'right' | 'left' | 'up' | 'down' | 'diagonal';
  borderColor?: string;
  hoverFillColor?: string;
  className?: string;
}

const Squares: React.FC<SquaresProps> = ({
  speed = 0.5,
  squareSize = 40,
  direction = 'right',
  borderColor = '#999',
  hoverFillColor = '#222',
  className
}) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number>();
  const numSquaresX = useRef<number>();
  const numSquaresY = useRef<number>();
  const gridOffset = useRef({ x: 0, y: 0 });
  const hoveredSquareRef = useRef<{ x: number; y: number } | null>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const resizeCanvas = () => {
      canvas.width = canvas.offsetWidth;
      canvas.height = canvas.offsetHeight;
      numSquaresX.current = Math.ceil(canvas.width / squareSize) + 1;
      numSquaresY.current = Math.ceil(canvas.height / squareSize) + 1;
    };

    window.addEventListener('resize', resizeCanvas);
    resizeCanvas();

    const drawGrid = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      const startX = Math.floor(gridOffset.current.x / squareSize) * squareSize - gridOffset.current.x % squareSize;
      const startY = Math.floor(gridOffset.current.y / squareSize) * squareSize - gridOffset.current.y % squareSize;

      for (let x = startX; x < canvas.width + squareSize; x += squareSize) {
        for (let y = startY; y < canvas.height + squareSize; y += squareSize) {
          const squareX = Math.floor((x - startX + gridOffset.current.x % squareSize) / squareSize);
          const squareY = Math.floor((y - startY + gridOffset.current.y % squareSize) / squareSize);

          if (
            hoveredSquareRef.current &&
            hoveredSquareRef.current.x === squareX &&
            hoveredSquareRef.current.y === squareY
          ) {
            ctx.fillStyle = hoverFillColor;
            ctx.fillRect(x, y, squareSize, squareSize);
          }

          ctx.strokeStyle = borderColor;
          ctx.strokeRect(x, y, squareSize, squareSize);
        }
      }
    };

    const updateGridOffset = () => {
      switch (direction) {
        case 'right': gridOffset.current.x = (gridOffset.current.x + speed) % squareSize; break;
        case 'left': gridOffset.current.x = (gridOffset.current.x - speed + squareSize) % squareSize; break;
        case 'up': gridOffset.current.y = (gridOffset.current.y - speed + squareSize) % squareSize; break;
        case 'down': gridOffset.current.y = (gridOffset.current.y + speed) % squareSize; break;
        case 'diagonal':
          gridOffset.current.x = (gridOffset.current.x + speed) % squareSize;
          gridOffset.current.y = (gridOffset.current.y + speed) % squareSize;
          break;
      }
    };

    const animate = () => {
      updateGridOffset();
      drawGrid();
      requestRef.current = requestAnimationFrame(animate);
    };

    const handleMouseMove = (event: MouseEvent) => {
      const rect = canvas.getBoundingClientRect();
      const mouseX = event.clientX - rect.left;
      const mouseY = event.clientY - rect.top;

      const startX = Math.floor(gridOffset.current.x / squareSize) * squareSize - gridOffset.current.x % squareSize;
      const startY = Math.floor(gridOffset.current.y / squareSize) * squareSize - gridOffset.current.y % squareSize;

      const hoveredX = Math.floor((mouseX - startX) / squareSize);
      const hoveredY = Math.floor((mouseY - startY) / squareSize);

      hoveredSquareRef.current = { x: hoveredX, y: hoveredY };
    };

    const handleMouseLeave = () => {
      hoveredSquareRef.current = null;
    };

    canvas.addEventListener('mousemove', handleMouseMove);
    canvas.addEventListener('mouseleave', handleMouseLeave);
    requestRef.current = requestAnimationFrame(animate);

    return () => {
      window.removeEventListener('resize', resizeCanvas);
      canvas.removeEventListener('mousemove', handleMouseMove);
      canvas.removeEventListener('mouseleave', handleMouseLeave);
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [direction, speed, squareSize, borderColor, hoverFillColor]);

  return (
    <canvas
      ref={canvasRef}
      className={`w-full h-full ${className ?? ''}`}
    />
  );
};

export default Squares;
```

## Demo
```tsx
import React from 'react';
import Squares from './Component';

export default function App() {
  return (
    <div className="w-full h-screen bg-[#060010] relative overflow-hidden">
      <Squares
        speed={0.5}
        squareSize={40}
        direction="diagonal"
        borderColor="#333"
        hoverFillColor="#5227FF"
      />
    </div>
  );
}
